            let mut m = indexmap::IndexMap::new();
                m.insert("auth".to_string(), Value::Null.clone());
                m.insert("connected".to_string(), Value::Null.clone());
                m.insert("tick".to_string(), Value::Null.clone());
                m.insert("ticker".to_string(), Value::Null.clone());
